SELECT * FROM "{{JSutils.currentSchema()}}".hotformpag001
WHERE formpag001_deleted <> true and formpag001_desc ILIKE '%{{TableImutipo.searchText}}%'
ORDER BY
{{
  ({
    formpag001_desc: 'formpag001_desc',
    formpag001_id: 'formpag001_id'
  }[TableImutipo.sortOrder.column]) || 'formpag001_desc'
}}
{{ TableImutipo.sortOrder.order === 'DESC' ? 'DESC' : 'ASC' }}
LIMIT {{TableImutipo.pageSize}}
OFFSET {{(TableImutipo.pageNo - 1) * TableImutipo.pageSize}};
